import{_ as n,o as i,c as t,ag as r}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Zeiterfassung","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/time-registration.md","filePath":"de/features/time-registration.md"}'),a={name:"de/features/time-registration.md"};function s(l,e,u,o,h,g){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="zeiterfassung" tabindex="-1">Zeiterfassung <a class="header-anchor" href="#zeiterfassung" aria-label="Permalink to &quot;Zeiterfassung&quot;">​</a></h1><p>Erfassen Sie Arbeitsstunden für Projekte und Kunden, um abrechenbare Zeit zu verfolgen und Rechnungen aus Zeiteinträgen zu erstellen.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Die Zeiterfassung hilft Ihnen:</p><ul><li>Zu verfolgen, wie viele Stunden Sie für jedes Projekt aufwenden</li><li>Abrechenbare vs. nicht abrechenbare Zeit zu berechnen</li><li>Rechnungen direkt aus erfassten Stunden zu erstellen</li><li>Ihren effektiven Stundensatz zu verstehen</li></ul><h2 id="zeit-erfassen" tabindex="-1">Zeit erfassen <a class="header-anchor" href="#zeit-erfassen" aria-label="Permalink to &quot;Zeit erfassen&quot;">​</a></h2><h3 id="zeiteintrag-erstellen" tabindex="-1">Zeiteintrag erstellen <a class="header-anchor" href="#zeiteintrag-erstellen" aria-label="Permalink to &quot;Zeiteintrag erstellen&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Zeiterfassung</strong></li><li>Klicken Sie auf <strong>Eintrag hinzufügen</strong> (oder die +-Schaltfläche auf Mobilgeräten)</li><li>Füllen Sie aus: <ul><li><strong>Datum</strong> — Wann die Arbeit erledigt wurde</li><li><strong>Stunden</strong> — Dauer der Arbeit</li><li><strong>Projekt</strong> — Für welches Projekt die Zeit ist</li><li><strong>Kunde</strong> — Der Kunde (wird automatisch aus dem Projekt ausgefüllt)</li><li><strong>Beschreibung</strong> — Woran Sie gearbeitet haben</li><li><strong>Abrechenbar</strong> — Ob diese Zeit in Rechnung gestellt werden soll</li><li><strong>Stundensatz</strong> — Ihr Satz für diese Arbeit</li></ul></li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><h3 id="nur-stunden-modus" tabindex="-1">Nur-Stunden-Modus <a class="header-anchor" href="#nur-stunden-modus" aria-label="Permalink to &quot;Nur-Stunden-Modus&quot;">​</a></h3><p>Für vereinfachte Zeiterfassung aktivieren Sie den Nur-Stunden-Modus in den Einstellungen. Dieser blendet die Felder für Stundensatz und Abrechenbarkeit aus und zeigt nur Stunden und Beschreibung an.</p><h2 id="zeiteintrage-abrechnen" tabindex="-1">Zeiteinträge abrechnen <a class="header-anchor" href="#zeiteintrage-abrechnen" aria-label="Permalink to &quot;Zeiteinträge abrechnen&quot;">​</a></h2><p>Wandeln Sie erfasste Stunden in Rechnungen um:</p><ol><li>Filtern Sie Zeiteinträge nach Kunde oder Projekt</li><li>Wählen Sie die Einträge aus, die Sie abrechnen möchten</li><li>Klicken Sie auf <strong>Rechnung erstellen</strong></li><li>Eine neue Rechnung wird mit Positionen aus den ausgewählten Zeiteinträgen vorausgefüllt</li><li>Überprüfen und versenden</li></ol><h3 id="auto-rechnungseinstellungen" tabindex="-1">Auto-Rechnungseinstellungen <a class="header-anchor" href="#auto-rechnungseinstellungen" aria-label="Permalink to &quot;Auto-Rechnungseinstellungen&quot;">​</a></h3><p>Konfigurieren Sie automatische Rechnungsstellung für Zeiteinträge:</p><ol><li>Gehen Sie zu den Zeiterfassungseinstellungen</li><li>Richten Sie Auto-Rechnungsregeln ein</li><li>Zeiteinträge, die den Regeln entsprechen, werden automatisch zu Rechnungen hinzugefügt</li></ol><h2 id="filtern" tabindex="-1">Filtern <a class="header-anchor" href="#filtern" aria-label="Permalink to &quot;Filtern&quot;">​</a></h2><p>Filtern Sie Ihre Zeiteinträge nach:</p><ul><li><strong>Kunde</strong> — Zeit pro Kunde anzeigen</li><li><strong>Projekt</strong> — Zeit pro Projekt anzeigen</li><li><strong>Datumsbereich</strong> — Bestimmter Zeitraum</li><li><strong>Abrechenbarkeitsstatus</strong> — Abrechenbar vs. nicht abrechenbar</li><li><strong>Rechnungsstatus</strong> — Abgerechnet vs. nicht abgerechnet</li></ul><h2 id="massenaktionen" tabindex="-1">Massenaktionen <a class="header-anchor" href="#massenaktionen" aria-label="Permalink to &quot;Massenaktionen&quot;">​</a></h2><ul><li><strong>Als abrechenbar markieren</strong> — Mehrere Einträge als abrechenbar setzen</li><li><strong>Rechnung erstellen</strong> — Mehrere Einträge auf einmal abrechnen</li><li><strong>Archivieren</strong> — Einträge ins Archiv verschieben</li><li><strong>Löschen</strong> — Einträge entfernen</li></ul><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Erfassen Sie Zeit täglich für genaue Aufzeichnungen</li><li>Verwenden Sie den Projektfilter, um Zeitsummen pro Projekt zu sehen</li><li>Überprüfen Sie regelmäßig nicht abgerechnete Zeit, um abrechenbare Stunden nicht zu verpassen</li><li>Das projektbasierte Dashboard-Profil hebt Zeiterfassungskennzahlen hervor</li></ul>',23)])])}const b=n(a,[["render",s]]);export{c as __pageData,b as default};
